from dataclasses import dataclass

@dataclass
class CostBudget:
    cost_per_request_usd: float   # target average cost
    cost_per_request_max: float   # hard ceiling; above this = feature not viable
    monthly_request_estimate: int
    monthly_cost_ceiling_usd: float

    def is_viable(self, actual_cost: float) -> bool:
        return actual_cost <= self.cost_per_request_max

    def monthly_projection(self, actual_cost: float) -> float:
        return actual_cost * self.monthly_request_estimate

@dataclass
class LatencyBudget:
    p50_ms: int
    p95_ms: int
    p99_ms: int
    timeout_ms: int   # hard timeout; request fails above this

CONTRACT_REVIEW_BUDGETS = {
    "cost": CostBudget(
        cost_per_request_usd=0.04,
        cost_per_request_max=0.10,
        monthly_request_estimate=5000,
        monthly_cost_ceiling_usd=500.0,
    ),
    "latency": LatencyBudget(
        p50_ms=3000,
        p95_ms=8000,
        p99_ms=15000,
        timeout_ms=30000,
    ),
}
